import { useEffect, useRef, useState, useCallback } from 'react';
import * as LWC from 'lightweight-charts';
const { createChart, CrosshairMode, CandlestickSeries } = LWC;

const C = {
  bg: '#0B0F14', surface: '#0F1620', border: '#1F2A37',
  text: '#E5E7DB', muted: '#90A3AF', green: '#22C55E',
  red: '#EF4444', blue: '#60A5FA', amber: '#F59E0B',
};
const mono = "'JetBrains Mono', monospace";

const LAYOUTS = {
  '1x1': { rows: 1, cols: 1 },
  '2x2': { rows: 2, cols: 2 },
  '2x3': { rows: 2, cols: 3 },
  '3x3': { rows: 3, cols: 3 },
};

const SYMBOLS = ['AAPL', 'MSFT', 'GOOGL', 'AMZN', 'TSLA', 'NVDA', 'META', 'JPM', 'V'];

function generateMockCandles(symbol, count) {
  const data = [];
  const base = Math.floor(Date.now() / 1000) - count * 86400;
  let open = 100 + (symbol.charCodeAt(0) % 50);
  for (let i = 0; i < count; i++) {
    const time = base + i * 86400;
    const close = open + (Math.random() - 0.5) * 4;
    const high = Math.max(open, close) + Math.random() * 2;
    const low = Math.min(open, close) - Math.random() * 2;
    data.push({ time, open, high, low, close: +close.toFixed(2) });
    open = close;
  }
  return data;
}

export default function MultiChartReplay() {
  const [layout, setLayout] = useState('2x2');
  const [symbols, setSymbols] = useState(() => {
    const count = LAYOUTS['2x2'].rows * LAYOUTS['2x2'].cols;
    return Array(count).fill(0).map((_, i) => SYMBOLS[i % SYMBOLS.length]);
  });
  const [playing, setPlaying] = useState(false);
  const [speed, setSpeed] = useState(1);
  const [barIndex, setBarIndex] = useState(100);
  const containersRef = useRef([]);
  const chartsRef = useRef([]);
  const totalBars = 200;

  const { rows, cols } = LAYOUTS[layout];
  const count = rows * cols;

  // Sync symbols array with layout
  useEffect(() => {
    setSymbols(prev => {
      if (prev.length >= count) return prev.slice(0, count);
      return [...prev, ...Array(count - prev.length).fill(0).map((_, i) => SYMBOLS[(prev.length + i) % SYMBOLS.length])];
    });
  }, [count]);

  // Create charts
  useEffect(() => {
    chartsRef.current.forEach(c => { try { c.chart.remove(); } catch {} });
    chartsRef.current = [];
    const newCharts = [];
    for (let i = 0; i < count; i++) {
      const container = containersRef.current[i];
      if (!container) continue;
      const chart = createChart(container, {
        width: container.clientWidth, height: container.clientHeight,
        layout: { background: { color: C.bg }, textColor: C.muted, fontFamily: mono, fontSize: 10 },
        grid: { vertLines: { color: C.border }, horzLines: { color: C.border } },
        crosshair: { mode: CrosshairMode.Normal },
        rightPriceScale: { borderColor: C.border },
        timeScale: { borderColor: C.border, visible: true },
      });
      const series = chart.addSeries(CandlestickSeries, {
        upColor: C.green, downColor: C.red, borderUpColor: C.green,
        borderDownColor: C.red, wickUpColor: C.green, wickDownColor: C.red,
      });
      const data = generateMockCandles(symbols[i], totalBars);
      series.setData(data.slice(0, barIndex));
      newCharts.push({ chart, series, data, symbol: symbols[i] });
    }
    chartsRef.current = newCharts;

    const ro = new ResizeObserver(() => {
      newCharts.forEach((c, i) => {
        const el = containersRef.current[i];
        if (el) c.chart.applyOptions({ width: el.clientWidth, height: el.clientHeight });
      });
    });
    containersRef.current.forEach(el => { if (el) ro.observe(el); });
    return () => { ro.disconnect(); newCharts.forEach(c => { try { c.chart.remove(); } catch {} }); };
  }, [symbols.join(','), count]);

  // Replay playback
  useEffect(() => {
    if (!playing) return;
    const interval = setInterval(() => {
      setBarIndex(prev => {
        const next = prev + 1;
        if (next >= totalBars) { setPlaying(false); return totalBars; }
        chartsRef.current.forEach(c => c.series.setData(c.data.slice(0, next)));
        return next;
      });
    }, 1000 / speed);
    return () => clearInterval(interval);
  }, [playing, speed]);

  const stepForward = () => {
    if (barIndex < totalBars) {
      const next = barIndex + 1;
      setBarIndex(next);
      chartsRef.current.forEach(c => c.series.setData(c.data.slice(0, next)));
    }
  };

  const stepBack = () => {
    if (barIndex > 10) {
      const next = barIndex - 1;
      setBarIndex(next);
      chartsRef.current.forEach(c => c.series.setData(c.data.slice(0, next)));
    }
  };

  const reset = () => {
    setBarIndex(10);
    setPlaying(false);
    chartsRef.current.forEach(c => c.series.setData(c.data.slice(0, 10)));
  };

  const changeSymbol = (idx, newSymbol) => {
    setSymbols(prev => { const n = [...prev]; n[idx] = newSymbol; return n; });
  };

  return (
    <div style={{ padding: 24, background: C.bg, minHeight: '100vh', color: C.text, fontFamily: mono }}>
      <h2 style={{ fontSize: 22, fontWeight: 700, marginBottom: 16 }}>Multi-Chart Replay</h2>

      {/* Toolbar */}
      <div style={{
        display: 'flex', gap: 12, alignItems: 'center', marginBottom: 16, padding: '10px 16px',
        background: C.surface, border: `1px solid ${C.border}`, borderRadius: 10,
      }}>
        <select value={layout} onChange={e => setLayout(e.target.value)}
          style={{ background: C.bg, border: `1px solid ${C.border}`, borderRadius: 6, padding: '4px 8px', color: C.text, fontFamily: mono, fontSize: 13 }}>
          {Object.keys(LAYOUTS).map(k => <option key={k} value={k}>{k}</option>)}
        </select>
        <div style={{ width: 1, height: 20, background: C.border }} />
        <button onClick={stepBack} style={{ background: 'transparent', border: `1px solid ${C.border}`, borderRadius: 6, padding: '4px 10px', color: C.text, cursor: 'pointer', fontFamily: mono, fontSize: 13 }}>
          ◀
        </button>
        <button onClick={() => setPlaying(!playing)}
          style={{ background: playing ? C.amber : C.green, border: 'none', borderRadius: 6, padding: '4px 14px', color: '#fff', cursor: 'pointer', fontFamily: mono, fontSize: 13, fontWeight: 600 }}>
          {playing ? 'Pause' : 'Play'}
        </button>
        <button onClick={stepForward} style={{ background: 'transparent', border: `1px solid ${C.border}`, borderRadius: 6, padding: '4px 10px', color: C.text, cursor: 'pointer', fontFamily: mono, fontSize: 13 }}>
          ▶
        </button>
        <button onClick={reset} style={{ background: 'transparent', border: `1px solid ${C.border}`, borderRadius: 6, padding: '4px 10px', color: C.muted, cursor: 'pointer', fontFamily: mono, fontSize: 11 }}>
          Reset
        </button>
        <div style={{ width: 1, height: 20, background: C.border }} />
        <span style={{ fontSize: 11, color: C.muted }}>Speed:</span>
        <select value={speed} onChange={e => setSpeed(Number(e.target.value))}
          style={{ background: C.bg, border: `1px solid ${C.border}`, borderRadius: 6, padding: '4px 8px', color: C.text, fontFamily: mono, fontSize: 13 }}>
          {[1, 2, 5, 10].map(s => <option key={s} value={s}>{s}x</option>)}
        </select>
        <span style={{ fontSize: 11, color: C.muted, marginLeft: 'auto' }}>Bar {barIndex}/{totalBars}</span>
      </div>

      {/* Chart Grid */}
      <div style={{
        display: 'grid', gridTemplateColumns: `repeat(${cols}, 1fr)`, gridTemplateRows: `repeat(${rows}, 1fr)`,
        gap: 8, height: 'calc(100vh - 200px)',
      }}>
        {Array(count).fill(0).map((_, i) => (
          <div key={i} style={{ background: C.surface, border: `1px solid ${C.border}`, borderRadius: 10, overflow: 'hidden', position: 'relative' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '4px 8px', background: `${C.surface}cc`, position: 'absolute', top: 0, left: 0, right: 0, zIndex: 2 }}>
              <select value={symbols[i] || SYMBOLS[0]} onChange={e => changeSymbol(i, e.target.value)}
                style={{ background: C.bg, border: `1px solid ${C.border}`, borderRadius: 6, padding: '2px 6px', color: C.text, fontFamily: mono, fontSize: 11 }}>
                {SYMBOLS.map(s => <option key={s} value={s}>{s}</option>)}
              </select>
            </div>
            <div ref={el => containersRef.current[i] = el} style={{ width: '100%', height: '100%' }} />
          </div>
        ))}
      </div>
    </div>
  );
}
